import express from 'express';
import path from 'path';
import http from 'http';
import { createServer as createViteServer } from 'vite';
import { GoogleGenAI, Type } from '@google/genai';
import dotenv from 'dotenv';

dotenv.config();

const app = express();
const PORT = 3000;

app.use(express.json());

// Initialize Gemini Client Lazily and Safely
let aiClient: GoogleGenAI | null = null;
function getGeminiClient(): GoogleGenAI | null {
  if (!aiClient && process.env.GEMINI_API_KEY) {
    try {
      aiClient = new GoogleGenAI({
        apiKey: process.env.GEMINI_API_KEY,
        httpOptions: {
          headers: {
            'User-Agent': 'aistudio-build',
          },
        },
      });
      console.log('Gemini AI Client initialized successfully.');
    } catch (e) {
      console.error('Failed to initialize Gemini Client:', e);
    }
  }
  return aiClient;
}

// Check if external WordNet service responds on port 8788
async function checkExternalWordNet(): Promise<boolean> {
  return new Promise((resolve) => {
    const req = http.get('http://127.0.0.1:8788/api/vocab/health', (res) => {
      resolve(res.statusCode === 200);
    });
    req.on('error', () => resolve(false));
    req.setTimeout(500, () => {
      req.destroy();
      resolve(false);
    });
  });
}

// Proxies a request to the local container sidecar on port 8788
async function proxyToWordNet(pathStr: string, res: express.Response) {
  const url = `http://127.0.0.1:8788${pathStr}`;
  const req = http.get(url, (proxyRes) => {
    res.writeHead(proxyRes.statusCode || 200, proxyRes.headers);
    proxyRes.pipe(res);
  });
  req.on('error', (err) => {
    res.status(502).json({ error: 'Proxy failed', message: err.message });
  });
  req.setTimeout(2000, () => {
    req.destroy();
    res.status(504).json({ error: 'Proxy timeout' });
  });
}

